// Optimization level (0-3), configurable via -O flag. Default: 0 (no optimization).
static int g_optimization_level = 0;

// Map user-facing optimization level to LLVM CodeGenOptLevel
#if LLVM_VERSION_MAJOR >= 18
static llvm::CodeGenOptLevel getCodeGenOptLevel() {
    switch (g_optimization_level) {
        case 0:  return llvm::CodeGenOptLevel::None;
        case 1:  return llvm::CodeGenOptLevel::Less;
        case 2:  return llvm::CodeGenOptLevel::Default;
        case 3:  return llvm::CodeGenOptLevel::Aggressive;
        default: return llvm::CodeGenOptLevel::None;
    }
}
#else
static llvm::CodeGenOpt::Level getCodeGenOptLevel() {
    switch (g_optimization_level) {
        case 0:  return llvm::CodeGenOpt::None;
        case 1:  return llvm::CodeGenOpt::Less;
        case 2:  return llvm::CodeGenOpt::Default;
        case 3:  return llvm::CodeGenOpt::Aggressive;
        default: return llvm::CodeGenOpt::None;
    }
}
#endif

// Map user-facing optimization level to LLVM PassBuilder OptimizationLevel
static llvm::OptimizationLevel getPassBuilderOptLevel() {
    switch (g_optimization_level) {
        case 0:  return llvm::OptimizationLevel::O0;
        case 1:  return llvm::OptimizationLevel::O1;
        case 2:  return llvm::OptimizationLevel::O2;
        case 3:  return llvm::OptimizationLevel::O3;
        default: return llvm::OptimizationLevel::O0;
    }
}

static llvm::Triple getModuleTargetTriple(const llvm::Module& module) {
#if LLVM_VERSION_MAJOR >= 21
    return module.getTargetTriple();
#else
    return llvm::Triple(module.getTargetTriple());
#endif
}

/* Coerce mismatched integer call-argument types to match each callee's
 * declared parameter type.  Necessary on the wasm32 target where many
 * arena_allocate callsites across backend codegen files emit
 * an i64 size argument while the function is declared with i32 size_t.
 * On native (size_t = i64) this loop is a near-no-op since types already
 * match; on wasm32 it inserts ZExt/Trunc to satisfy the LLVM verifier
 * before WASM codegen runs.
 *
 * Only direct calls with a known Function callee are touched.  Only
 * IntegerType vs IntegerType mismatches are fixed; pointer/FP arg
 * mismatches indicate a real codegen bug and are left for the verifier
 * to reject loudly.  Variadic args past the fixed parameter count are
 * not coerced (they have no declared type to match).
 *
 * Centralising here is the architectural fix that doesn't require
 * touching the 144 callsites individually — they all funnel through
 * this pass before module verification.
 */
static void coerceCallArgIntegerTypes(llvm::Module& module) {
    using namespace llvm;
    // Two-phase to avoid any iterator-invalidation footgun: collect candidate
    // CallInsts first, then mutate.  Insertions from CreateZExtOrTrunc would
    // otherwise land inside the BB we're iterating over.
    SmallVector<CallInst*, 32> calls;
    for (Function& F : module) {
        for (BasicBlock& BB : F) {
            for (Instruction& I : BB) {
                if (auto* CI = dyn_cast<CallInst>(&I)) calls.push_back(CI);
            }
        }
    }
    for (CallInst* CI : calls) {
        Function* callee = CI->getCalledFunction();
        if (!callee) continue;  // indirect call
        FunctionType* FT = callee->getFunctionType();
        unsigned fixed = FT->getNumParams();
        IRBuilder<> builder(CI);
        for (unsigned i = 0; i < CI->arg_size(); ++i) {
            if (i >= fixed) break;  // variadic tail — no declared type
            Value* arg = CI->getArgOperand(i);
            Type* expected = FT->getParamType(i);
            Type* actual = arg->getType();
            if (actual == expected) continue;
            auto* aIT = dyn_cast<IntegerType>(actual);
            auto* eIT = dyn_cast<IntegerType>(expected);
            if (!aIT || !eIT) continue;  // not an int↔int mismatch
            Value* coerced = builder.CreateZExtOrTrunc(arg, expected,
                arg->hasName() ? arg->getName() + ".coerced" : Twine("arg.coerced"));
            CI->setArgOperand(i, coerced);
        }
    }
}

/* Coerce invalid integer binary-operator operands back to the instruction's
 * result type before verification.  The wasm32 target exposes this when byte
 * sizes are computed from i64 tensor/vector lengths and i32 size_t constants
 * (for example: `mul i64 %len, i32 8`).  LLVM's verifier rejects that IR, and
 * the intent at those callsites is a byte count in the result width.
 */
static void coerceIntegerBinaryOperandTypes(llvm::Module& module) {
    using namespace llvm;

    SmallVector<BinaryOperator*, 32> binary_ops;
    for (Function& F : module) {
        for (BasicBlock& BB : F) {
            for (Instruction& I : BB) {
                if (auto* BO = dyn_cast<BinaryOperator>(&I)) {
                    binary_ops.push_back(BO);
                }
            }
        }
    }

    for (BinaryOperator* BO : binary_ops) {
        auto* result_type = dyn_cast<IntegerType>(BO->getType());
        if (!result_type) continue;

        IRBuilder<> builder(BO);
        for (unsigned i = 0; i < 2; ++i) {
            Value* operand = BO->getOperand(i);
            if (operand->getType() == result_type) continue;

            auto* operand_type = dyn_cast<IntegerType>(operand->getType());
            if (!operand_type) continue;

            Value* coerced = nullptr;
            if (auto* constant = dyn_cast<ConstantInt>(operand)) {
                coerced = ConstantInt::get(
                    result_type,
                    constant->getValue().zextOrTrunc(result_type->getBitWidth()));
            } else {
                coerced = builder.CreateZExtOrTrunc(
                    operand,
                    result_type,
                    operand->hasName()
                        ? operand->getName() + ".binop.coerced"
                        : Twine("binop.coerced"));
            }
            BO->setOperand(i, coerced);
        }
    }
}

// Run LLVM optimization passes on a module before codegen
static void optimizeModule(llvm::Module& module, llvm::TargetMachine* TM, bool is_wasm = false) {
    // Always coerce mismatched integer types first.  On native this is a no-op;
    // on wasm32 it fixes size_t (i32) vs i64 mismatches that would otherwise
    // fail module verification before WASM emission.
    coerceCallArgIntegerTypes(module);
    coerceIntegerBinaryOperandTypes(module);

    auto opt_level = getPassBuilderOptLevel();

    llvm::PassBuilder PB(TM);

    llvm::LoopAnalysisManager LAM;
    llvm::FunctionAnalysisManager FAM;
    llvm::CGSCCAnalysisManager CGAM;
    llvm::ModuleAnalysisManager MAM;

    PB.registerModuleAnalyses(MAM);
    PB.registerCGSCCAnalyses(CGAM);
    PB.registerFunctionAnalyses(FAM);
    PB.registerLoopAnalyses(LAM);
    PB.crossRegisterProxies(LAM, FAM, CGAM, MAM);

    if (opt_level == llvm::OptimizationLevel::O0) {
        const llvm::Triple module_triple = getModuleTargetTriple(module);
        const bool is_windows_arm64 =
            module_triple.getArch() == llvm::Triple::aarch64 &&
            module_triple.isOSWindows();
        if (!is_wasm && is_windows_arm64) {
            // The native cleanup pipeline is needed for deep CPS on the Unix
            // targets, but it can exceed the Windows ARM64 lite smoke compile
            // budget on AD-heavy modules before the linker is reached.
            eshkol_info("Skipped LLVM O0 cleanup passes for Windows ARM64 target");
            return;
        }
        llvm::ModulePassManager MPM;
        const char* cleanup_pipeline = is_wasm
            ? "default<O1>"
            : "function(sroa,early-cse,instcombine<no-verify-fixpoint>,simplifycfg)";
        if (auto err = PB.parsePassPipeline(MPM, cleanup_pipeline)) {
            llvm::consumeError(std::move(err));
            eshkol_warn("Failed to parse LLVM O0 cleanup pipeline; continuing without cleanup");
            return;
        }
        MPM.run(module, MAM);
        eshkol_info("Applied LLVM O0 cleanup passes");
    } else {
        llvm::ModulePassManager MPM = PB.buildPerModuleDefaultPipeline(opt_level);
        MPM.run(module, MAM);
        eshkol_info("Applied LLVM optimization passes at -O%d", g_optimization_level);
    }
}

// Dead-strip a standalone wasm module before emission.
//
// A wasm object emitted by eshkol-run bundles its stdlib as ordinary
// (external-linkage) function definitions. Nothing links the object
// afterwards — there is no wasm-ld --gc-sections pass — so on its own the
// per-module optimizer keeps every external symbol (they might be referenced
// by another translation unit) and the entire stdlib survives even when the
// program uses only a handful of functions.
//
// For a self-contained module loaded via WebAssembly.instantiate() only the
// declared exports (main / scheme_main / _start) can be reached from outside.
// Internalize everything else, then run GlobalDCE: any function or global not
// transitively reachable from an export — including unused stdlib — is removed.
// Functions that ARE used as first-class values keep a live ptrtoint reference
// at the use site, so they survive; only genuinely-unreachable code is dropped.
//
// This pairs with wasm codegen skipping the homoiconic display registry
// (homoiconicRegistryEnabled()): without that, main() would ptrtoint every
// top-level function and defeat the DCE below.
static void deadStripWasmModule(llvm::Module& module) {
    auto must_preserve = [](const llvm::GlobalValue& gv) -> bool {
        llvm::StringRef name = gv.getName();
        if (name == "main" || name == "scheme_main" || name == "_start") {
            return true;
        }
        if (const auto* fn = llvm::dyn_cast<llvm::Function>(&gv)) {
            if (fn->hasFnAttribute("wasm-export-name")) {
                return true;
            }
        }
        return false;
    };

    llvm::LoopAnalysisManager LAM;
    llvm::FunctionAnalysisManager FAM;
    llvm::CGSCCAnalysisManager CGAM;
    llvm::ModuleAnalysisManager MAM;

    llvm::PassBuilder PB;
    PB.registerModuleAnalyses(MAM);
    PB.registerCGSCCAnalyses(CGAM);
    PB.registerFunctionAnalyses(FAM);
    PB.registerLoopAnalyses(LAM);
    PB.crossRegisterProxies(LAM, FAM, CGAM, MAM);

    llvm::ModulePassManager MPM;
    MPM.addPass(llvm::InternalizePass(must_preserve));
    MPM.addPass(llvm::GlobalDCEPass());
    MPM.run(module, MAM);
    eshkol_info("Applied wasm dead-strip (internalize + globalDCE)");
}

