using namespace llvm;

struct ScopedObjectTempFile {
    std::string path;
    bool keep = false;

    explicit ScopedObjectTempFile(std::string temp_path)
        : path(std::move(temp_path)) {}

    ~ScopedObjectTempFile() {
        if (!keep && !path.empty()) {
            (void)sys::fs::remove(path);
        }
    }

    void dismiss() {
        keep = true;
    }
};

// Global storage for LLVM contexts to ensure proper lifetime management
struct EshkolLLVMModule {
    std::unique_ptr<LLVMContext> context;
    std::unique_ptr<Module> module;
    
    EshkolLLVMModule(std::unique_ptr<Module> mod, std::unique_ptr<LLVMContext> ctx) 
        : context(std::move(ctx)), module(std::move(mod)) {}
};

static std::unordered_map<LLVMModuleRef, std::unique_ptr<EshkolLLVMModule>> g_llvm_modules;

// STDLIB LINKAGE: Flag to track whether the program uses stdlib
// When set, the generated code will call __eshkol_lib_init__ for homoiconic display
static bool g_uses_stdlib = false;

// DEBUG INFO: Flag to enable DWARF debug info generation
// When set, the compiler emits DIBuilder metadata for source-level debugging (lldb, gdb)
static bool g_emit_debug_info = false;
static std::string g_debug_source_filename;
static std::string g_debug_source_directory;
// Source text + filepath for structured error messages with caret display
static std::string g_source_text;
static std::string g_source_filepath;

struct AotModuleStats {
    uint64_t functions = 0;
    uint64_t definitions = 0;
    uint64_t globals = 0;
    uint64_t basic_blocks = 0;
    uint64_t instructions = 0;
};

static bool env_flag_enabled(const char* name) {
    const char* raw = std::getenv(name);
    return raw && raw[0] != '\0' && std::strcmp(raw, "0") != 0 &&
           std::strcmp(raw, "false") != 0 && std::strcmp(raw, "FALSE") != 0;
}

static unsigned int object_emit_timeout_seconds() {
    const char* raw = std::getenv("ESHKOL_OBJECT_EMIT_TIMEOUT_SECONDS");
    if (!raw || raw[0] == '\0') {
        return 0;
    }

    char* end = nullptr;
    long parsed = std::strtol(raw, &end, 10);
    if (end && *end == '\0' && parsed >= 0) {
        return static_cast<unsigned int>(parsed);
    }

    eshkol_warn("Ignoring invalid ESHKOL_OBJECT_EMIT_TIMEOUT_SECONDS=%s", raw);
    return 0;
}

static AotModuleStats collect_aot_module_stats(const Module& module) {
    AotModuleStats stats;
    for (const Function& function : module) {
        stats.functions++;
        if (function.isDeclaration()) {
            continue;
        }
        stats.definitions++;
        for (const BasicBlock& block : function) {
            stats.basic_blocks++;
            stats.instructions += static_cast<uint64_t>(block.size());
        }
    }
    for (auto it = module.global_begin(); it != module.global_end(); ++it) {
        stats.globals++;
    }
    return stats;
}

static void print_object_emit_context(const char* prefix,
                                      const char* phase,
                                      const char* note,
                                      unsigned int timeout_seconds,
                                      const std::string& module_id,
                                      const char* source,
                                      const AotModuleStats& stats,
                                      const char* output_filename,
                                      const std::string& temp_filename,
                                      const std::string& target_triple,
                                      const std::string& cpu_name,
                                      int optimization_level,
                                      long long elapsed_ms = -1) {
    const char* output = output_filename ? output_filename : "unknown";
    const char* temp = temp_filename.empty() ? "none" : temp_filename.c_str();
    const char* target = target_triple.empty() ? "unknown" : target_triple.c_str();
    const char* cpu = cpu_name.empty() ? "unknown" : cpu_name.c_str();

    std::fprintf(stderr,
                 "%s phase=%s timeout_seconds=%u elapsed_ms=%lld source=%s "
                 "module=%s output=%s temp=%s target=%s cpu=%s opt=-O%d "
                 "functions=%llu definitions=%llu globals=%llu "
                 "basic_blocks=%llu instructions=%llu note=%s\n",
                 prefix,
                 phase ? phase : "unknown",
                 timeout_seconds,
                 elapsed_ms,
                 source,
                 module_id.empty() ? "unknown" : module_id.c_str(),
                 output,
                 temp,
                 target,
                 cpu,
                 optimization_level,
                 static_cast<unsigned long long>(stats.functions),
                 static_cast<unsigned long long>(stats.definitions),
                 static_cast<unsigned long long>(stats.globals),
                 static_cast<unsigned long long>(stats.basic_blocks),
                 static_cast<unsigned long long>(stats.instructions),
                 note ? note : "");
    std::fflush(stderr);
}

static void trace_object_emit_phase(const char* phase,
                                    const char* event,
                                    const Module& module,
                                    const char* output_filename,
                                    const std::string& temp_filename,
                                    const std::string& target_triple,
                                    const std::string& cpu_name,
                                    long long elapsed_ms = -1) {
    if (!env_flag_enabled("ESHKOL_AOT_PHASE_TRACE")) {
        return;
    }
    AotModuleStats stats = collect_aot_module_stats(module);
    std::string module_id = module.getModuleIdentifier();
    const char* source = g_source_filepath.empty() ? "unknown" : g_source_filepath.c_str();
    std::string prefix = std::string("ESH-0088: AOT object emission ") +
                         (event ? event : "trace");
    print_object_emit_context(prefix.c_str(),
                              phase,
                              "phase trace",
                              object_emit_timeout_seconds(),
                              module_id,
                              source,
                              stats,
                              output_filename,
                              temp_filename,
                              target_triple,
                              cpu_name,
                              g_optimization_level,
                              elapsed_ms);
}

class ScopedObjectEmitWatchdog {
public:
    ScopedObjectEmitWatchdog(unsigned int timeout_seconds,
                             const Module& module,
                             const char* output_filename,
                             std::string temp_filename,
                             std::string target_triple,
                             std::string cpu_name)
        : timeout_seconds_(timeout_seconds),
          module_id_(module.getModuleIdentifier()),
          source_(g_source_filepath.empty() ? "unknown" : g_source_filepath),
          stats_(collect_aot_module_stats(module)),
          output_filename_(output_filename ? output_filename : ""),
          temp_filename_(std::move(temp_filename)),
          target_triple_(std::move(target_triple)),
          cpu_name_(std::move(cpu_name)),
          optimization_level_(g_optimization_level),
          start_(std::chrono::steady_clock::now()) {
        if (timeout_seconds_ == 0) {
            return;
        }
        thread_ = std::thread([this]() { run(); });
    }

    ~ScopedObjectEmitWatchdog() {
        finish();
    }

    void set_phase(const char* phase, const char* note) {
        if (timeout_seconds_ == 0) {
            return;
        }
        std::lock_guard<std::mutex> lock(mutex_);
        phase_ = phase ? phase : "unknown";
        note_ = note ? note : "";
    }

    void finish() {
        if (timeout_seconds_ == 0) {
            return;
        }
        {
            std::lock_guard<std::mutex> lock(mutex_);
            done_ = true;
        }
        cv_.notify_all();
        if (thread_.joinable()) {
            thread_.join();
        }
        timeout_seconds_ = 0;
    }

private:
    void run() {
        std::unique_lock<std::mutex> lock(mutex_);
        const bool completed = cv_.wait_for(
            lock,
            std::chrono::seconds(timeout_seconds_),
            [this]() { return done_; });
        if (completed) {
            return;
        }

        const std::string phase = phase_;
        const std::string note = note_;
        lock.unlock();

        const auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start_);
        print_object_emit_context(
            "ESH-0088: LLVM object emission watchdog timed out",
            phase.c_str(),
            note.empty()
                ? "stalled inside LLVM backend object emission; final object was not published"
                : note.c_str(),
            timeout_seconds_,
            module_id_,
            source_.c_str(),
            stats_,
            output_filename_.c_str(),
            temp_filename_,
            target_triple_,
            cpu_name_,
            optimization_level_,
            elapsed.count());

        if (!temp_filename_.empty()) {
            std::remove(temp_filename_.c_str());
        }
        std::_Exit(124);
    }

    unsigned int timeout_seconds_ = 0;
    std::string module_id_;
    std::string source_;
    AotModuleStats stats_;
    std::string output_filename_;
    std::string temp_filename_;
    std::string target_triple_;
    std::string cpu_name_;
    int optimization_level_ = 0;
    std::chrono::steady_clock::time_point start_;
    std::mutex mutex_;
    std::condition_variable cv_;
    bool done_ = false;
    std::string phase_ = "setup";
    std::string note_ = "";
    std::thread thread_;
};

// Emit a codegen error with source location from an AST node.
// Falls back to plain eshkol_error if no source location available.
__attribute__((format(printf, 2, 3)))
static void codegen_error_at(const eshkol_ast_t* ast, const char* msg, ...) {
    char buffer[2048];
    va_list ap;
    va_start(ap, msg);
    vsnprintf(buffer, sizeof(buffer), msg, ap);
    va_end(ap);

    if (ast && ast->line > 0) {
        eshkol_error_at(
            g_source_filepath.empty() ? nullptr : g_source_filepath.c_str(),
            ast->line, ast->column,
            g_source_text.empty() ? nullptr : g_source_text.c_str(),
            "%s", buffer);
    } else {
        eshkol_error("%s", buffer);
    }
}

// REPL MODE: Global symbol persistence across CodeGenerator instances
// When REPL mode is enabled, symbols persist across evaluations
namespace {
    bool g_repl_mode_enabled = false;
    std::unordered_map<std::string, uint64_t> g_repl_symbol_addresses;     // var_name -> JIT address
    std::unordered_map<std::string, uint64_t> g_repl_function_addresses;   // func_name -> JIT address
    std::unordered_map<std::string, size_t> g_repl_function_arities;       // func_name -> arity
    std::unordered_map<std::string, std::string> g_repl_lambda_names;      // var_name -> lambda_name (e.g., "square" -> "lambda_name")
    std::unordered_map<std::string, uint64_t> g_repl_sexpr_values;         // sexpr_name -> s-expression pointer value
    std::unordered_map<std::string, std::vector<std::string>> g_repl_lambda_captures;  // lambda_name -> capture variable names
    std::unordered_map<std::string, std::pair<size_t, bool>> g_repl_variadic_functions;  // func_name -> (fixed_params, is_variadic)
    std::unordered_set<std::string> g_repl_private_symbols;                // Private symbols (not exported from modules)
    // ── REPL HOT RELOAD ──────────────────────────────────────────────────────
    // The REPL implements live redefinition for ALL top-level bindings using
    // PLT/GOT-style indirection: every reachable binding name resolves at the
    // JIT linker level to a heap slot owned by the REPL host. Redefinition
    // updates the slot's contents; previously-compiled callers automatically
    // pick up the new value on their next access.
    //
    //   Functions  ((define (f x) ...))         → __repl_fwd_<name> slot holds
    //                                              a function pointer; the call
    //                                              site does load+indirect call.
    //                                              Each definition compiles a
    //                                              uniquely-named body
    //                                              (`<name>__rv<N>`) so JIT
    //                                              materialization never sees a
    //                                              symbol clash.
    //
    //   Variables  ((define x 5),                → @<name> is emitted as a pure
    //               (define f (lambda ...)))       external declaration. The
    //                                              REPL host allocates a 16-byte
    //                                              tagged_value heap slot on
    //                                              first definition and registers
    //                                              `@__repl_storage_<name>`
    //                                              as an absolute JIT symbol
    //                                              pointing to it. Stores and
    //                                              loads of that private symbol
    //                                              then naturally write to / read
    //                                              from the shared heap location,
    //                                              so redefinition is just a
    //                                              store. The private storage
    //                                              name avoids clashes with LLVM
    //                                              functions like `log2`.
    //                                              The marker global
    //                                              `__repl_var_<name>` tells the
    //                                              host which externals to back
    //                                              with heap storage.
    std::unordered_set<std::string> g_repl_user_function_names;
    std::unordered_set<std::string> g_repl_user_variable_names;
    std::atomic<int> g_repl_define_counter{0};                             // Monotonic version counter for REPL user functions
    // Functions registered via eshkol_repl_register_native_c_function: their
    // symbols name a C function (compiled by clang/gcc) that takes/returns
    // eshkol_tagged_value_t under the platform C ABI. Clang lowers a 16-byte
    // tagged_value to `[2 x i64]` for AAPCS / SysV register passing, NOT to
    // the IR struct `{i8,i8,i16,i32,i64}` that the JIT uses for Eshkol-to-
    // Eshkol calls. If we declared these C functions with the IR struct ABI,
    // the JIT would pass each field in a separate GPR while the C function
    // expects two i64 GPRs holding the packed bytes, scrambling the args.
    //
    // tryResolveReplFunction() detects membership in this set and emits a
    // thin coercion thunk (struct-ABI on the JIT side, [2 x i64] ABI on the
    // C side) so existing call sites stay untouched. See the comment block
    // in tryResolveReplFunction() for the full coercion sequence.
    std::unordered_set<std::string> g_repl_native_c_functions;
    std::mutex g_repl_mutex;  // Thread safety for REPL symbol access

    static std::string replVarStorageSymbolName(const std::string& name) {
        std::string out = "__repl_storage_";
        char encoded[4];
        for (unsigned char ch : name) {
            if (std::isalnum(ch)) {
                out.push_back(static_cast<char>(ch));
            } else {
                std::snprintf(encoded, sizeof(encoded), "_%02X", ch);
                out += encoded;
            }
        }
        return out;
    }

    // Compute the LLVM symbol name used to back a top-level user variable's
    // storage. User-program globals MUST NOT be emitted under their raw Scheme
    // name: a name like `free`/`malloc`/`exit` would collide with the C runtime
    // symbol at JIT/AOT link (calling data as code -> SIGBUS at teardown), and a
    // name like `log`/`sin` would clash with an in-module libm function
    // declaration (LLVM auto-renames the GlobalVariable, and two creation sites
    // then produce two distinct `@log.N` slots — a `set!` writes one while a
    // read sees the other, so mutations are silently lost on cached-JIT/AOT).
    // Mangling the symbol removes the whole collision class. See ESH-0092/0103.
    //
    //   is_repl   -> private REPL storage (`__repl_storage_*`, hot-reload aware)
    //   is_public -> raw name (library `provide` bindings and `:external`
    //                references, which must bind cross-object to stdlib.o)
    //   otherwise -> `eshkol_g_`-prefixed, encoded so it can never equal a
    //                C/libm symbol.
    static std::string userGlobalStorageName(const std::string& name,
                                             bool is_repl, bool is_public) {
        if (is_repl) {
            return replVarStorageSymbolName(name);
        }
        if (is_public) {
            return name;
        }
        std::string out = "eshkol_g_";
        char encoded[4];
        for (unsigned char ch : name) {
            if (std::isalnum(ch)) {
                out.push_back(static_cast<char>(ch));
            } else {
                std::snprintf(encoded, sizeof(encoded), "_%02X", ch);
                out += encoded;
            }
        }
        return out;
    }

    static void seedTypeCheckerWithReplFunctions(
        eshkol::hott::TypeChecker& type_checker,
        eshkol::hott::TypeEnvironment& type_env) {
        struct ReplFunctionType {
            std::string name;
            size_t arity;
            bool is_variadic;
        };

        std::vector<ReplFunctionType> functions;
        {
            std::lock_guard<std::mutex> lock(g_repl_mutex);
            if (!g_repl_mode_enabled) {
                return;
            }

            functions.reserve(g_repl_function_arities.size());
            for (const auto& [name, arity] : g_repl_function_arities) {
                if (g_repl_user_variable_names.find(name) !=
                    g_repl_user_variable_names.end()) {
                    continue;
                }

                size_t fixed_arity = arity;
                bool is_variadic = false;
                auto variadic_it = g_repl_variadic_functions.find(name);
                if (variadic_it != g_repl_variadic_functions.end() &&
                    variadic_it->second.second) {
                    fixed_arity = variadic_it->second.first;
                    is_variadic = true;
                }

                functions.push_back({name, fixed_arity, is_variadic});
            }
        }

        for (const auto& fn : functions) {
            std::vector<eshkol::hott::TypeId> params(
                fn.arity, eshkol::hott::BuiltinTypes::Value);
            type_checker.context().bind(
                fn.name,
                type_env.makeFunctionType(
                    params,
                    eshkol::hott::BuiltinTypes::Value,
                    fn.is_variadic));
        }
    }

    /* REPL LAST-VALUE CAPTURE
     *
     * Bug (2026-05-08, qLLM bridge): top-level expressions evaluated by the
     * REPL JIT (no user-defined `main`) had their results discarded — the
     * generated `main` always emitted `ret i32 0` at line ~2069 below, no
     * matter what the last expression returned. Symptom: every call to
     * eshkol_eval_string("42", ...) and eshkol_eval_string("(+ 1 2)", ...)
     * came back with type=INT64 (correct) but data.int_val=0 (wrong).
     *
     * Fix: codegen now emits a runtime call to
     * eshkol_repl_capture_last_value() after each top-level expression. The
     * JIT-side captures the tagged value into the thread-local slot below.
     * ReplJITContext::executeTagged then reads the slot in preference to
     * the truncated-i32 main return.
     *
     * Thread-local because the REPL JIT may run on multiple worker threads
     * (test fixtures, agent contexts) and each must see only its own value.
     */
    thread_local eshkol_tagged_value_t g_repl_last_value{
        ESHKOL_VALUE_NULL, 0, 0, {.raw_val = 0}
    };
    thread_local bool g_repl_last_value_set = false;

    // External library function registry
    // Populated by eshkol_register_external_functions(), consumed during codegen
    struct ExternalFuncInfo {
        size_t num_params;      // Number of fixed parameters
        bool is_variadic;       // Whether function accepts variadic arguments
    };
    std::unordered_map<std::string, ExternalFuncInfo> g_external_functions;
    std::mutex g_external_mutex;

    // CACHED TARGET INFO: Avoid recomputing on every compilation
    bool g_target_info_cached = false;
    std::string g_cached_target_triple;
    std::string g_cached_cpu_name;
    std::string g_cached_features;
    bool g_freestanding_codegen = false;
}

// TypedValue structure to carry both LLVM value and type information
struct TypedValue {
    Value* llvm_value;              // LLVM IR value
    eshkol_value_type_t type;       // Our type tag from eshkol.h
    bool is_exact;                  // Scheme exactness tracking
    uint8_t flags;                  // Additional flags (e.g., indirect reference flag)
    eshkol::hott::TypeId hott_type; // HoTT compile-time type (for gradual typing)

    // HoTT PARAMETERIZED TYPE: For tracking List<Int64>, Vector<Float64>, etc.
    // This is optional - only set for collection types with known element types
    std::optional<eshkol::hott::ParameterizedType> param_type;

    // Flag constants
    static constexpr uint8_t FLAG_INDIRECT = 0x01;  // Value is address of global to load from
    static constexpr uint8_t FLAG_LINEAR   = 0x02;  // Must be consumed exactly once (linear type)
    static constexpr uint8_t FLAG_PROOF    = 0x04;  // Compile-time only, erased at runtime

    TypedValue()
        : llvm_value(nullptr), type(ESHKOL_VALUE_NULL), is_exact(true), flags(0),
          hott_type(eshkol::hott::BuiltinTypes::Null), param_type(std::nullopt) {}

    TypedValue(Value* val, eshkol_value_type_t t, bool exact = true, uint8_t f = 0)
        : llvm_value(val), type(t), is_exact(exact), flags(f),
          hott_type(eshkol::hott::BuiltinTypes::Value), param_type(std::nullopt) {}

    // Constructor with explicit HoTT type
    TypedValue(Value* val, eshkol_value_type_t t, eshkol::hott::TypeId hott_t, bool exact = true, uint8_t f = 0)
        : llvm_value(val), type(t), is_exact(exact), flags(f), hott_type(hott_t), param_type(std::nullopt) {}

    // Constructor with parameterized type (for List<T>, Vector<T>, etc.)
    TypedValue(Value* val, eshkol_value_type_t t, eshkol::hott::TypeId hott_t,
               const eshkol::hott::ParameterizedType& ptype, bool exact = true, uint8_t f = 0)
        : llvm_value(val), type(t), is_exact(exact), flags(f), hott_type(hott_t), param_type(ptype) {}

    // Helper methods
    bool isInt64() const { return type == ESHKOL_VALUE_INT64; }
    bool isDouble() const { return type == ESHKOL_VALUE_DOUBLE; }
    bool isNull() const { return type == ESHKOL_VALUE_NULL; }
    bool isIndirect() const { return (flags & FLAG_INDIRECT) != 0; }

    // HoTT type helpers
    bool hasKnownType() const { return hott_type != eshkol::hott::BuiltinTypes::Value; }
    bool isHottInt64() const { return hott_type == eshkol::hott::BuiltinTypes::Int64; }
    bool isHottFloat64() const { return hott_type == eshkol::hott::BuiltinTypes::Float64; }
    bool isHottNumeric() const {
        return hott_type == eshkol::hott::BuiltinTypes::Int8 ||
               hott_type == eshkol::hott::BuiltinTypes::Int16 ||
               hott_type == eshkol::hott::BuiltinTypes::Int32 ||
               hott_type == eshkol::hott::BuiltinTypes::Int64 ||
               hott_type == eshkol::hott::BuiltinTypes::ISize ||
               hott_type == eshkol::hott::BuiltinTypes::UInt8 ||
               hott_type == eshkol::hott::BuiltinTypes::UInt16 ||
               hott_type == eshkol::hott::BuiltinTypes::UInt32 ||
               hott_type == eshkol::hott::BuiltinTypes::UInt64 ||
               hott_type == eshkol::hott::BuiltinTypes::USize ||
               hott_type == eshkol::hott::BuiltinTypes::Float64 ||
               hott_type == eshkol::hott::BuiltinTypes::Integer ||
               hott_type == eshkol::hott::BuiltinTypes::Real ||
               hott_type == eshkol::hott::BuiltinTypes::Number;
    }

    // HoTT parameterized type helpers
    bool hasParameterizedType() const { return param_type.has_value(); }
    eshkol::hott::TypeId elementType() const {
        if (param_type.has_value()) {
            return param_type->elementType();
        }
        return eshkol::hott::BuiltinTypes::Value;
    }
    // M1 Migration: Check both legacy and consolidated formats
    bool isList() const { return type == ESHKOL_VALUE_HEAP_PTR || type == ESHKOL_VALUE_HEAP_PTR; }
    bool isVector() const { return type == ESHKOL_VALUE_HEAP_PTR || type == ESHKOL_VALUE_HEAP_PTR; }

    // Linear and proof type helpers (HoTT Phase 4)
    bool isLinear() const { return (flags & FLAG_LINEAR) != 0; }
    bool isProof() const { return (flags & FLAG_PROOF) != 0; }
    bool shouldErase() const { return isProof(); }  // Proofs are erased at runtime

    // Create an erased value (for proof types that don't exist at runtime)
    static TypedValue makeErased(eshkol::hott::TypeId proof_type) {
        return TypedValue(nullptr, ESHKOL_VALUE_NULL, proof_type, true, FLAG_PROOF);
    }

    // Create an erased value with a unit placeholder (for contexts that need a valid LLVM value)
    static TypedValue makeErasedWithPlaceholder(llvm::Value* unit_value, eshkol::hott::TypeId proof_type) {
        return TypedValue(unit_value, ESHKOL_VALUE_NULL, proof_type, true, FLAG_PROOF);
    }
};

// OPTION 3: Deferred Lambda S-Expression Generation
// Structure to track lambdas that need S-expression generation
struct LambdaSExprMetadata {
    const eshkol_operations_t* lambda_ast;
    std::string lambda_name;
};

// Global vector to accumulate lambdas during compilation
static std::vector<LambdaSExprMetadata> pending_lambda_sexprs;

// Track the most recently generated lambda name for codegenList
static std::string last_generated_lambda_name;

// HOMOICONIC FIX: Map lambda Function* pointers to their S-expression global names
// This allows codegenList to find the correct S-expression for each inline lambda
static std::unordered_map<Function*, std::string> lambda_sexpr_map;

// MEMOIZATION FIX: Map AST operation pointers to their lambda names
// This prevents exponential IR generation when processing nested lambdas in S-expression generation
static std::unordered_map<const eshkol_operations_t*, std::string> lambda_ast_to_name;

static constexpr size_t LIB_INIT_AST_CHUNK_SIZE = 4;
static constexpr size_t LIB_INIT_LAMBDA_SEXPR_CHUNK_SIZE = 4;

// Helper function to check if a function name is a lambda name
// Handles both old format "lambda_N" and new format "prefix_lambda_N"
static bool isLambdaName(const std::string& name) {
    // Check for "_lambda_" anywhere (new format with module prefix)
    if (name.find("_lambda_") != std::string::npos) return true;
    // Check for "lambda_" at start (old format, still supported)
    if (name.find("lambda_") == 0) return true;
    return false;
}

static GlobalValue::LinkageTypes publicDefinitionLinkage(bool library_mode) {
    // REPL mode: use ExternalLinkage so the ResourceTracker-based hot-reload
    // path in ReplJITContext::addModule can actually replace definitions on
    // redefine. linkonce_odr would cause LLVM ORC to silently keep the first
    // definition (the "one definition rule" semantics), which defeats hot
    // reload — redefined functions would still point to the old code.
    if (g_repl_mode_enabled) {
        return GlobalValue::ExternalLinkage;
    }
    return library_mode
        ? GlobalValue::LinkOnceODRLinkage
        : GlobalValue::ExternalLinkage;
}

static GlobalValue::LinkageTypes sexprGlobalLinkage(
    bool library_mode,
    GlobalValue::LinkageTypes local_non_windows = GlobalValue::LinkOnceODRLinkage
) {
#ifdef _WIN32
    if (library_mode || g_repl_mode_enabled) {
        return GlobalValue::WeakAnyLinkage;
    }
    return GlobalValue::InternalLinkage;
#else
    return (library_mode || g_repl_mode_enabled)
        ? GlobalValue::LinkOnceODRLinkage
        : local_non_windows;
#endif
}

// Forward declaration for callback wrappers
class EshkolLLVMCodeGen;

// Static callback wrappers for ControlFlowCodegen
// These allow the extracted module to call back into the main codegen
namespace ControlFlowCallbacks {
    // Wrapper for codegenAST - returns LLVM Value*
    static llvm::Value* codegenASTWrapper(const void* ast, void* context);
    // Wrapper for codegenTypedAST - returns pointer to TypedValue (caller owns)
    static void* codegenTypedASTWrapper(const void* ast, void* context);
    // Wrapper for typedValueToTaggedValue
    static llvm::Value* typedToTaggedWrapper(void* typed_value, void* context);
    // Wrapper for codegenNestedFunctionDefinition
    static void codegenFuncDefineWrapper(const void* op, void* context);
    // Wrapper for codegenVariableDefinition
    static void codegenVarDefineWrapper(const void* op, void* context);
    // Wrapper for callBuiltinEqv
    static llvm::Value* eqvCompareWrapper(llvm::Value* a, llvm::Value* b, void* context);
    // Wrapper for detectValueType + typedValueToTaggedValue
    static llvm::Value* detectAndPackWrapper(llvm::Value* val, void* context);
    // Wrapper for codegenTaggedArenaConsCellFromTaggedValue
    static llvm::Value* consCreateWrapper(llvm::Value* car, llvm::Value* cdr, void* context);
    // Wrapper to get TypedValue type
    static int getTypedValueTypeWrapper(void* typed_value, void* context);
    // Wrapper to register function binding
    static void registerFuncBindingWrapper(const char* var_name, void* typed_value, void* context);
    // Wrapper for extractConsCarAsTaggedValue (for CallApplyCodegen)
    static llvm::Value* extractConsCarWrapper(llvm::Value* cons_ptr, void* context);
    // Wrapper for getTaggedConsGetPtrFunc (for CallApplyCodegen)
    static llvm::Function* getConsAccessorWrapper(void* context);
    // Wrapper for codegenAST with typed signature (for CallApplyCodegen)
    static llvm::Value* codegenASTTypedWrapper(const eshkol_ast_t* ast, void* context);
    // Wrappers for MapCodegen
    static llvm::Value* codegenLambdaWrapper(const eshkol_operations_t* op, void* context);
    static llvm::Value* closureCallWrapper(llvm::Value* closure, const std::vector<llvm::Value*>& args, void* context);
    static llvm::Value* closureCallWithInfoWrapper(llvm::Value* closure, const std::vector<llvm::Value*>& args, const char* info, void* context);
    static llvm::Function* getClosureAllocWrapper(void* context);
    static llvm::Function* getConsSetPtrWrapper(void* context);
    static llvm::Value* resolveLambdaWrapper(const eshkol_ast_t* ast, size_t arity, void* context);
    static llvm::Value* indirectCallWrapper(llvm::Value* arg, size_t arity, void* context);
    static void pushFunctionContextWrapper(void* context);
    static void popFunctionContextWrapper(void* context);
    // TCO callback for checking self-tail-recursion
    static bool isSelfTailRecursiveWrapper(const void* lambda_op, const char* func_name, void* context);
    // Wrapper for getting builtin arithmetic functions (for CallApplyCodegen)
    static llvm::Function* getBuiltinArithmeticWrapper(const std::string& op, void* context);
    // Wrapper for resolving comparison/equality/predicate builtins (for apply)
    static llvm::Function* getBuiltinPredicateWrapper(const std::string& name, void* context);
    // Wrapper for applying tensor/vector builtin functions
    static llvm::Value* applyBuiltinWrapper(const std::string& func_name, const std::vector<llvm::Value*>& args, llvm::Value* arg_count, void* context);
    // Bug P (2026-04-23): wrapper for forward-ref apply (cross-file user defines)
    static llvm::Value* applyForwardRefWrapper(const std::string& func_name, llvm::Value* list_int, void* context);
}

