        // ============================================================================
        // SYSTEM & ENVIRONMENT FUNCTIONS (from stdlib.h, unistd.h)
        // ============================================================================

        // getenv: char* eshkol_getenv(const char* name)
        std::vector<Type*> getenv_args;
